"""Core pipeline and task abstractions."""
from dataclasses import dataclass, field
from typing import Any, Callable, Optional
from enum import Enum


class TaskStatus(Enum):
    PENDING = "pending"
    RUNNING = "running"
    COMPLETED = "completed"
    FAILED = "failed"
    SKIPPED = "skipped"


@dataclass
class TaskResult:
    status: TaskStatus
    output: Any = None
    error: Optional[str] = None
    duration_ms: float = 0


@dataclass
class Task:
    name: str
    fn: Callable
    depends_on: list[str] = field(default_factory=list)
    timeout: float = 30.0
    retries: int = 0
    _status: TaskStatus = field(default=TaskStatus.PENDING, init=False)

    def run(self, **kwargs) -> TaskResult:
        import time
        start = time.time()
        try:
            result = self.fn(**kwargs)
            elapsed = (time.time() - start) * 1000
            self._status = TaskStatus.COMPLETED
            return TaskResult(TaskStatus.COMPLETED, output=result, duration_ms=elapsed)
        except Exception as e:
            elapsed = (time.time() - start) * 1000
            self._status = TaskStatus.FAILED
            return TaskResult(TaskStatus.FAILED, error=str(e), duration_ms=elapsed)


class Pipeline:
    def __init__(self, name: str = "default"):
        self.name = name
        self.tasks: dict[str, Task] = {}
        self._results: dict[str, TaskResult] = {}

    def add_task(self, task: Task):
        self.tasks[task.name] = task

    def get_execution_order(self) -> list[str]:
        """Topological sort of tasks."""
        visited = set()
        order = []

        def visit(name):
            if name in visited:
                return
            visited.add(name)
            task = self.tasks[name]
            for dep in task.depends_on:
                if dep in self.tasks:
                    visit(dep)
            order.append(name)

        for name in self.tasks:
            visit(name)
        return order

    def run(self, **kwargs) -> dict[str, TaskResult]:
        order = self.get_execution_order()
        for name in order:
            task = self.tasks[name]
            # Check dependencies
            deps_ok = all(
                self._results.get(d, TaskResult(TaskStatus.FAILED)).status == TaskStatus.COMPLETED
                for d in task.depends_on
            )
            if not deps_ok:
                self._results[name] = TaskResult(TaskStatus.SKIPPED)
                continue
            self._results[name] = task.run(**kwargs)
        return self._results

